// Parse error payload from n8n Error Trigger
const execError = $input.first().json;
const customData = execError.execution?.customData || {};

// Classify severity by workflow name
const wfName = execError.workflow?.name || '';
const severity = (() => {
  if (wfName.includes('hris-intake') || wfName.includes('it-approval')) return 'CRITICAL';
  if (wfName.includes('account-provisioning') || wfName.includes('role-classifier')) return 'HIGH';
  return 'LOW';
})();

const severityEmoji = { CRITICAL: '🚨', HIGH: '⚠️', LOW: '📋' }[severity];

const hireContext = customData.hire_id
  ? `*Hire:* ${customData.full_name || 'Unknown'} \`${customData.hire_id}\``
  : '_No hire context — error occurred before hire_id was set_';

const slackText = [
  `${severityEmoji} *[${severity}] Onboarding Pipeline Error*`,
  ``,
  `*Workflow:* ${execError.workflow?.name || 'Unknown'}`,
  `*Failed Node:* ${execError.execution?.lastNodeExecuted || 'Unknown'}`,
  `*Error:* ${execError.execution?.error?.message || 'Unknown error'}`,
  hireContext,
  `*Execution ID:* \`${execError.execution?.id || 'Unknown'}\``,
  `*Time:* ${new Date().toISOString()}`
].join('\n');

return [{
  json: {
    severity,
    slackText,
    workflowName: execError.workflow?.name || 'Unknown',
    hireId: customData.hire_id || null,
    fullName: customData.full_name || null,
    errorMessage: execError.execution?.error?.message || 'Unknown error',
    timestamp: new Date().toISOString()
  }
}];
